// ==========================================
// CONFIGURATION
// ==========================================

const USE_MOCK = false; 

// Smarter API URL logic: 
// 1. If we are on a local-like domain, assume backend is on port 5000.
// 2. Otherwise use relative path '/api'.
const isLocal = window.location.hostname === 'localhost' || 
                window.location.hostname === '127.0.0.1' || 
                window.location.hostname.startsWith('192.168.') || 
                window.location.hostname.startsWith('10.') ||
                window.location.hostname.endsWith('.local');

const API_URL = isLocal ? `http://${window.location.hostname}:5000/api` : '/api';

// ==========================================
// REQUEST HELPER
// ==========================================

const getHeaders = () => {
    const token = localStorage.getItem('uniparty_token');
    return {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : ''
    };
};

/**
 * Robust fetch wrapper that handles non-OK responses and JSON parsing errors
 */
async function request(path: string, options: RequestInit = {}) {
    const url = path.startsWith('http') ? path : `${API_URL}${path}`;

    try {
        const response = await fetch(url, {
            ...options,
            headers: {
                ...getHeaders(),
                ...(options.headers || {})
            }
        });

        // Handle non-OK responses (4xx, 5xx)
        if (!response.ok) {
            let errorMessage = `Request failed with status ${response.status}`;
            try {
                const errorData = await response.json();
                errorMessage = errorData.error || errorMessage;
            } catch (e) {
                // If not JSON, try to get text
                const text = await response.text();
                if (text && text.length < 100) errorMessage = text;
            }
            throw new Error(errorMessage);
        }

        // Handle 204 No Content
        if (response.status === 204) return null;

        // Safely parse JSON
        const contentType = response.headers.get('content-type');
        if (contentType && contentType.includes('application/json')) {
            try {
                return await response.json();
            } catch (err: any) {
                console.error(`JSON Parse Error at ${url}:`, err);
                throw new Error(`Invalid response from server (JSON parse error)`);
            }
        }

        return await response.text();
    } catch (error: any) {
        console.error(`API Request Error [${url}]:`, error.message);
        throw error;
    }
}

