app.post('/api/reports', authMiddleware, async (req, res) => {
    const report = await Report.create({ eventId: req.body.eventId, reporterId: req.user.userId, reason: req.body.reason });
    res.json(report);
});

app.get('/api/admin/reports', authMiddleware, adminMiddleware, async (req, res) => {
    const reports = await Report.find({ status: 'pending' }).populate('eventId', 'title organization image').populate('reporterId', 'name email').sort({ createdAt: -1 });
