app.post('/api/users/follow/toggle', authMiddleware, async (req, res) => {
    const { associationId } = req.body;
    const student = await User.findById(req.user.userId);
    const assoc = await User.findById(associationId);
    if (!assoc || assoc.role !== 'associazione') return res.status(404).json({ error: "Not found" });

    const isFollowing = student.followedAssociations.includes(associationId);
    if (isFollowing) {
        student.followedAssociations = student.followedAssociations.filter(id => id.toString() !== associationId);
        assoc.followersCount = Math.max(0, (assoc.followersCount || 0) - 1);
    } else {
        student.followedAssociations.push(associationId);
        assoc.followersCount = (assoc.followersCount || 0) + 1;
    }
    await student.save();
    await assoc.save();
    const updated = await User.findById(req.user.userId).populate('followedAssociations', 'name profileImage');
    res.json(updated.followedAssociations);
});

