app.post('/api/tickets/validate', authMiddleware, async (req, res) => {
    const { qrCodeId } = req.body;
    const ticket = await Ticket.findOne({ qrCodeId }).populate('event');
    if (!ticket || ticket.status === 'deleted') return res.status(404).json({ error: "Invalid" });

    const orgId = ticket.event.organization.toString();
    if (orgId !== req.user.userId && (!req.user.parentOrganization || req.user.parentOrganization.toString() !== orgId)) {
        return res.status(403).json({ error: "Forbidden" });
    }

    const type = ticket.event.scanType || 'entry_only';
    if (type === 'entry_only') {
        if (ticket.used) return res.status(400).json({ error: "ALREADY_USED" });
        ticket.used = true;
        ticket.status = 'completed';
        ticket.entryTime = new Date();
    } else {
        if (ticket.status === 'valid') {
            ticket.status = 'entered';
            ticket.entryTime = new Date();
        } else if (ticket.status === 'entered') {
            ticket.status = 'completed';
            ticket.exitTime = new Date();
            ticket.used = true;
        } else {
            return res.status(400).json({ error: "ALREADY_USED" });
        }
    }
    await ticket.save();
    res.json(ticket);
});

